export default function parseScannedCCCDData(raw) {
  if (typeof raw !== "string") return null;
  try {
    const queryStart = raw.indexOf("?");
    if (queryStart === -1) return null;
    const queryString = raw.substring(queryStart + 1); // lấy phần sau dấu ?
    const params = queryString.split("&");
    if (params.length < 2) return null;
    const obj = {};
    params.forEach(p => {
      const [k, v] = p.split("=");
      obj[k] = v;
    });
    if (obj.memberId && obj.memberType) {
      return {
        memberId: obj.memberId,
        memberType: obj.memberType,
      };
    }
  } catch {
    return null;
  }
  return null;
}
