import { DeleteOutlined, ScanOutlined, UploadOutlined } from "@ant-design/icons"
import { Button, Card, message, Spin, Typography } from "antd"
import jsQR from "jsqr"
import PropTypes from "prop-types"
import { useEffect, useRef, useState } from "react"
import { useNavigate, useSearchParams } from "react-router-dom"
import GuestService from "src/services/GuestService"
import DisplayCCCDInfo from "../DisplayCCCDInfo"
import parseScannedCCCDData from "../parseScannedCCCDData"

const { Text } = Typography

const UploadTab = ({
  onImageUploaded,
  title = "Upload ảnh QR Code",
  description = "Chọn ảnh chứa QR code để quét thông tin",
  acceptedFormats = "image/*",
  maxFileSize = 10,
  showPreview = true,
}) => {
  const navigate = useNavigate()
  const [searchParams] = useSearchParams()

  const [isProcessing, setIsProcessing] = useState(false)
  const [previewImage, setPreviewImage] = useState(null)
  const [, setQrRawData] = useState(null)
  const [parsedMemberData, setParsedMemberData] = useState(null)
  const [error, setError] = useState(null)
  const fileInputRef = useRef(null)

  // Validate file type and size
  const validateFile = file => {
    if (!file.type.startsWith("image/")) throw new Error("Vui lòng chọn file hình ảnh!")
    const fileSizeMB = file.size / 1024 / 1024
    if (fileSizeMB > maxFileSize) throw new Error(`Kích thước file phải nhỏ hơn ${maxFileSize}MB!`)
    return true
  }

  // Convert file to ImageData for jsQR scan
  const fileToImageData = file =>
    new Promise((resolve, reject) => {
      const reader = new FileReader()
      reader.onload = e => {
        const img = new Image()
        img.onload = () => {
          const canvas = document.createElement("canvas")
          const ctx = canvas.getContext("2d")
          canvas.width = img.width
          canvas.height = img.height
          ctx.drawImage(img, 0, 0)
          const imageData = ctx.getImageData(0, 0, canvas.width, canvas.height)
          resolve(imageData)
        }
        img.onerror = () => reject(new Error("Không thể đọc file ảnh"))
        img.src = e.target.result
      }
      reader.onerror = () => reject(new Error("Không thể đọc file"))
      reader.readAsDataURL(file)
    })

  // Scan QR code from image data
  const scanQRFromImage = async imageData => {
    try {
      const qrCode = jsQR(imageData.data, imageData.width, imageData.height)
      if (qrCode) {
        return { success: true, data: qrCode.data, location: qrCode.location }
      }
      return { success: false, error: "Không tìm thấy QR code trong ảnh" }
    } catch (error) {
      return { success: false, error: "Lỗi khi quét QR code: " + error.message }
    }
  }

  // Xử lý file upload / drop
  const handleFileSelect = async file => {
    console.log("🔥 Processing file:", file.name)
    setIsProcessing(true)
    setError(null)
    setQrRawData(null)
    setParsedMemberData(null)

    try {
      validateFile(file)

      const previewUrl = URL.createObjectURL(file)
      setPreviewImage(previewUrl)

      if (onImageUploaded) onImageUploaded(file, previewUrl)

      const imageData = await fileToImageData(file)
      const scanResult = await scanQRFromImage(imageData)

      if (!scanResult.success) {
        throw new Error(scanResult.error || "Không tìm thấy QR code trong ảnh")
      }

      const qrContent = scanResult.data
      setQrRawData(qrContent)

      const parsed = parseScannedCCCDData(qrContent)

      if (!parsed?.memberId || !parsed?.memberType) {
        throw new Error("QR không hợp lệ hoặc thiếu thông tin.")
      }

      const res = await GuestService.getMemberDetail({
        memberId: parsed.memberId,
        memberType: parsed.memberType,
      })

      if (res?.isError || !res?.Object) {
        throw new Error("Không tìm thấy thông tin hội viên.")
      }

      setParsedMemberData(res.Object)
      message.success("Tải thông tin hội viên thành công!")

      // Cập nhật URL query params, không reload trang
      navigate(`?memberId=${parsed.memberId}&memberType=${parsed.memberType}`, {
        replace: false,
      })
    } catch (error) {
      setError(error.message)
      message.error(error.message)
    } finally {
      setIsProcessing(false)
    }
  }

  // Xử lý khi input file thay đổi
  const handleFileChange = e => {
    const file = e.target.files[0]
    if (file) handleFileSelect(file)
  }

  // Kéo thả file
  const handleDrop = e => {
    e.preventDefault()
    const file = e.dataTransfer.files[0]
    if (file) handleFileSelect(file)
  }

  const handleDragOver = e => e.preventDefault()

  // Reset toàn bộ trạng thái và input file
  const handleClear = () => {
    setPreviewImage(null)
    setQrRawData(null)
    setParsedMemberData(null)
    setError(null)
    fileInputRef.current.value = ""
    // Xóa query params khỏi URL khi reset
    navigate(window.location.pathname, { replace: true })
  }

  // Tự động load dữ liệu nếu có query params
  useEffect(() => {
    const memberId = searchParams.get("memberId")
    const memberType = searchParams.get("memberType")

    if (memberId && memberType && !parsedMemberData) {
      const fetchMember = async () => {
        setIsProcessing(true)
        setError(null)
        try {
          const res = await GuestService.getMemberDetail({ memberId, memberType })
          if (res?.isError || !res?.Object) throw new Error("Không tìm thấy thông tin hội viên.")
          setParsedMemberData(res.Object)
        } catch (error) {
          message.error(error.message)
        } finally {
          setIsProcessing(false)
        }
      }

      fetchMember()
    }
  }, [searchParams, parsedMemberData, navigate])

  const triggerFileInput = () => fileInputRef.current?.click()

  // Nếu đã có dữ liệu hội viên thì hiển thị luôn
  if (parsedMemberData) {
    return (
      <DisplayCCCDInfo
        memberData={parsedMemberData}
        onBack={handleClear}
        onViewMemberCard={() => console.log("🪪 View member card clicked")}
      />
    )
  }

  return (
    <div className="qr-upload-scanner">
      <Card
        hoverable
        className="upload-card"
        style={{
          border: previewImage ? "2px solid #52c41a" : "2px dashed #009688",
          position: "relative",
        }}
        onDrop={handleDrop}
        onDragOver={handleDragOver}
      >
        <Spin spinning={isProcessing} tip="Đang xử lý...">
          <div className="upload-content text-center">
            {!previewImage && (
              <div
                onClick={triggerFileInput}
                style={{
                  cursor: "pointer",
                  display: "flex",
                  flexDirection: "column",
                  justifyContent: "center",
                  alignItems: "center",
                }}
              >
                <UploadOutlined
                  style={{
                    fontSize: "48px",
                    color: "#009688",
                    marginBottom: "16px",
                  }}
                />
                <h4 style={{ marginBottom: "8px" }}>{title}</h4>
                <Text type="secondary" style={{ fontSize: "14px" }}>
                  {description}
                </Text>
                <Text type="secondary" style={{ fontSize: "12px", marginTop: "8px" }}>
                  Kéo thả file hoặc click để chọn • Tối đa {maxFileSize}MB
                </Text>
              </div>
            )}

            {previewImage && !parsedMemberData && (
              <div style={{ textAlign: "left" }}>
                <div
                  style={{
                    display: "flex",
                    justifyContent: "space-between",
                    alignItems: "center",
                    marginBottom: "16px",
                  }}
                >
                  <Text strong>
                    <ScanOutlined style={{ marginRight: "8px" }} /> Kết quả quét QR
                  </Text>
                  <Button
                    type="text"
                    icon={<DeleteOutlined />}
                    onClick={handleClear}
                    size="small"
                  >
                    Xóa
                  </Button>
                </div>

                {showPreview && (
                  <div
                    style={{
                      textAlign: "center",
                      marginBottom: "16px",
                      padding: "16px",
                      backgroundColor: "#fafafa",
                      borderRadius: "8px",
                    }}
                  >
                    <img
                      src={previewImage}
                      alt="QR Preview"
                      style={{
                        maxWidth: "100%",
                        maxHeight: "200px",
                        objectFit: "contain",
                        border: "1px solid #d9d9d9",
                        borderRadius: "4px",
                      }}
                    />
                  </div>
                )}

                {error && (
                  <div
                    style={{
                      marginBottom: "16px",
                      padding: "16px",
                      backgroundColor: "#fff2f0",
                      border: "1px solid #ffccc7",
                      borderRadius: "8px",
                    }}
                  >
                    <Text type="danger">❌ {error}</Text>
                  </div>
                )}

                <Button
                  type="dashed"
                  onClick={triggerFileInput}
                  style={{ width: "100%" }}
                  disabled={isProcessing}
                >
                  <UploadOutlined /> Chọn ảnh khác
                </Button>
              </div>
            )}
          </div>
        </Spin>

        <input
          ref={fileInputRef}
          type="file"
          accept={acceptedFormats}
          onChange={handleFileChange}
          style={{ display: "none" }}
        />
      </Card>
    </div>
  )
}

UploadTab.propTypes = {
  onQRScanned: PropTypes.func,
  onImageUploaded: PropTypes.func,
  title: PropTypes.string,
  description: PropTypes.string,
  acceptedFormats: PropTypes.string,
  maxFileSize: PropTypes.number,
  showPreview: PropTypes.bool,
}

export default UploadTab
