import { ScanOutlined } from "@ant-design/icons"
import { Input, Typography, message } from "antd"
import { useEffect, useRef, useState } from "react"
import { useNavigate, useSearchParams } from "react-router-dom"
import DisplayCCCDInfo from "../DisplayCCCDInfo"
import parseScannedCCCDData from "../parseScannedCCCDData"
import GuestService from "src/services/GuestService"

const { Title, Text, Paragraph } = Typography

const ScanTab = () => {
  const [inputValue, setInputValue] = useState("")
  const [cccdData, setCccdData] = useState(null)
  const [, setLoading] = useState(false)
  const inputRef = useRef(null)

  const navigate = useNavigate()
  const [searchParams] = useSearchParams()

  useEffect(() => {
    inputRef.current?.focus()
  }, [])

  // Tự động load khi có params trong URL
  useEffect(() => {
    const memberId = searchParams.get("memberId")
    const memberType = searchParams.get("memberType")

    if (memberId && memberType && !cccdData) {
      const fetchMember = async () => {
        setLoading(true)
        try {
          const res = await GuestService.getMemberDetail({ memberId, memberType })
          if (res?.isError || !res?.Object) {
            message.error("Không tìm thấy thông tin hội viên.")
            return
          }
          setCccdData(res.Object)
        } catch (error) {
          message.error("Có lỗi xảy ra khi lấy thông tin.")
          console.error("Lỗi khi lấy thông tin hội viên:", error)
        } finally {
          setLoading(false)
        }
      }

      fetchMember()
    }
  }, [searchParams, cccdData])

  const handleSearch = async value => {
    if (!value) return

    const parsed = parseScannedCCCDData(value)

    if (!parsed?.memberId || !parsed?.memberType) {
      message.error("Dữ liệu không hợp lệ hoặc thiếu thông tin.")
      return
    }

    setLoading(true)
    try {
      const res = await GuestService.getMemberDetail({
        memberId: parsed.memberId,
        memberType: parsed.memberType,
      })

      if (res?.isError) {
        message.error("Không tìm thấy thông tin hội viên.")
        return
      }

      setCccdData(res?.Object)
      setInputValue("")

      // Cập nhật URL query params khi tìm thành công
      navigate(
        `?memberId=${parsed.memberId}&memberType=${parsed.memberType}`,
        { replace: false }
      )
    } catch (err) {
      message.error("Có lỗi xảy ra khi lấy thông tin.")
      console.error("Lỗi khi lấy thông tin hội viên:", err)
    } finally {
      setLoading(false)
    }
  }

  // Khi nhấn Back, reset state và xóa query params
  const handleBack = () => {
    setCccdData(null)
    navigate(window.location.pathname, { replace: true })
  }

  return cccdData ? (
    <DisplayCCCDInfo
      memberData={cccdData}
      onBack={handleBack}
      onViewMemberCard={() => console.log("Xem thẻ hội viên")}
    />
  ) : (
    <div
      style={{
        padding: "40px 24px",
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        minHeight: "60vh",
        background: "#f9fafb",
      }}
    >
      <div
        style={{
          width: 120,
          height: 120,
          borderRadius: "50%",
          background: "linear-gradient(135deg, #3b82f6, #06b6d4)",
          boxShadow: "0 8px 20px rgba(0, 191, 255, 0.25)",
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          cursor: "pointer",
          marginBottom: 24,
          transition: "transform 0.3s",
        }}
        onClick={() => inputRef.current?.focus()}
        onMouseEnter={e => (e.currentTarget.style.transform = "scale(1.05)")}
        onMouseLeave={e => (e.currentTarget.style.transform = "scale(1)")}
      >
        <ScanOutlined style={{ fontSize: 40, color: "white" }} />
      </div>

      <Title level={3} style={{ marginBottom: 8, color: "#1f2937" }}>
        Quét QR Hội Viên bằng máy quét
      </Title>
      <Text type="secondary">Đưa QR Hội Viên vào máy quét</Text>

      <Input
        ref={inputRef}
        value={inputValue}
        onChange={e => setInputValue(e.target.value)}
        onKeyDown={e => {
          if (e.key === "Enter") {
            handleSearch(e.target.value)
          }
        }}
        placeholder="Dán dữ liệu vào đây hoặc quét"
        size="large"
        style={{
          maxWidth: 480,
          marginTop: 32,
          borderRadius: 10,
          boxShadow: "0 2px 8px rgba(0,0,0,0.06)",
          fontSize: 16,
        }}
      />

      <div style={{ maxWidth: 600, marginTop: 40 }}>
        <Title level={4} style={{ color: "#334155", marginBottom: 24 }}>
          📘 Hướng Dẫn Sử Dụng
        </Title>
        <div
          style={{
            background: "#ffffff",
            borderRadius: 12,
            padding: "24px",
            boxShadow: "0 4px 12px rgba(0,0,0,0.08)",
          }}
        >
          {[
            "Đưa QR của hội viên vào máy quét mã vạch/QR.",
            "Hệ thống sẽ tự động xử lý và hiển thị thông tin.",
            "Kiểm tra thông tin và tiếp tục các bước tiếp theo nếu cần.",
          ].map((step, index) => (
            <div
              key={index}
              style={{
                display: "flex",
                alignItems: "center",
                marginBottom: 16,
                gap: 16,
              }}
            >
              <div
                style={{
                  width: 32,
                  height: 32,
                  borderRadius: "50%",
                  background: "#3b82f6",
                  color: "white",
                  display: "flex",
                  alignItems: "center",
                  justifyContent: "center",
                  fontWeight: "bold",
                  fontSize: 16,
                }}
              >
                {index + 1}
              </div>
              <Paragraph
                style={{
                  margin: 0,
                  color: "#1f2937",
                  fontSize: 16,
                  lineHeight: 1.6,
                }}
              >
                {step}
              </Paragraph>
            </div>
          ))}
        </div>
      </div>
    </div>
  )
}

export default ScanTab
