import { CameraOutlined, QrcodeOutlined, ScanOutlined, UploadOutlined } from "@ant-design/icons"
import { Card, Col, message, Row, Tabs, Typography } from "antd"
import { useCallback, useState } from "react"
import ScanQR from "src/components/ScannerQr"
import { parseIDCardData } from "src/pages/USER/IndividualRegistration/utils/cccdUtils"
import styled from "styled-components"
import CameraTab from "./components/CameraScan/CameraTab"
import ScanTab from "./components/Scan/ScanTab"
import UploadTab from "./components/Upload/UploadTab"
import DisplayCCCDInfo from "./components/DisplayCCCDInfo"

const { Title, Text } = Typography
const { TabPane } = Tabs

// Styled components for custom styles
const StyledCard = styled(Card)`
  border-radius: 20px;
  box-shadow: 0 8px 24px rgba(0, 0, 0, 0.1);
  overflow: hidden;
  transition: transform 0.3s ease;

  &:hover {
    transform: translateY(-4px);
  }
`

const ERROR_MESSAGES = {
  SCAN_SUCCESS: "Quét CCCD thành công!",
  SCAN_ERROR: "Có lỗi xảy ra khi xử lý dữ liệu CCCD",
  VALIDATION_ERROR: "Vui lòng quét CCCD trước khi tiếp tục",
  UPLOAD_ERROR: "Có lỗi xảy ra khi xử lý ảnh CCCD",
  HARDWARE_SCAN_ERROR: "Có lỗi xảy ra khi quét bằng máy scan"
}

const handleQRScanned = (data, location, file) => {
  console.log("📦 QR DATA:", data)
  // Có thể xử lý thêm nếu muốn lưu vào state
}

const handleImageUploaded = (file, previewUrl) => {
  console.log("🖼️ Ảnh đã được chọn:", file.name, previewUrl)
}

const ScanQRInfo = ({ form, next }) => {
  const [scanState, setScanState] = useState({
    isScanning: false,
    isProcessing: false,
    isCompleted: false,
    cccdData: null
  })

  const [displayState, setDisplayState] = useState({
    isVisible: false,
    stepData: null
  })

  const updateFormWithCCCDData = useCallback((parsedData) => {
    form.setFieldsValue({
      cccdId: parsedData.id,
      fullName: parsedData.name,
      birthDate: parsedData.birthDate,
      gender: parsedData.gender,
      issueDate: parsedData.issueDate,
      originalAddress: parsedData.address
    })
  }, [form])

  const processCCCDData = useCallback(async (data) => {
    setScanState(prev => ({ ...prev, isProcessing: true }))
    try {
      const parsedData = parseIDCardData(data)
      setScanState(prev => ({
        ...prev,
        cccdData: parsedData,
        isCompleted: true
      }))
      updateFormWithCCCDData(parsedData)
      message.success(ERROR_MESSAGES.SCAN_SUCCESS)
      return parsedData
    } catch (error) {
      console.error("CCCD data processing error:", error)
      message.error(ERROR_MESSAGES.SCAN_ERROR)
      return null
    } finally {
      setScanState(prev => ({ ...prev, isProcessing: false }))
    }
  }, [updateFormWithCCCDData])

  // Camera Scan Handlers
  const handleCameraScanResult = useCallback((data) => {
    if (!data.raw) return
    processCCCDData(data.raw)
    setScanState(prev => ({ ...prev, isScanning: false }))
  }, [processCCCDData])

  const handleOpenCamera = useCallback(() => {
    setScanState(prev => ({ ...prev, isScanning: true }))
  }, [])

  const handleCloseCameraScan = useCallback(() => {
    setScanState(prev => ({ ...prev, isScanning: false }))
  }, [])

  // Hardware Scan Handler
  const handleHardwareScan = useCallback(async () => {
    setScanState(prev => ({ ...prev, isProcessing: true }))
    try {
      // Placeholder for hardware scanner integration
      const scannedData = "mock_hardware_scan_data" // Replace with actual scanner data
      await processCCCDData(scannedData)
    } catch (error) {
      console.error("Hardware scan error:", error)
      message.error(ERROR_MESSAGES.HARDWARE_SCAN_ERROR)
    } finally {
      setScanState(prev => ({ ...prev, isProcessing: false }))
    }
  }, [processCCCDData])

  const handleConfirm = useCallback(() => {
    if (!scanState.isCompleted || !scanState.cccdData) {
      message.error(ERROR_MESSAGES.VALIDATION_ERROR)
      return
    }
    const stepData = {
      cccdData: scanState.cccdData
    }
    setDisplayState({ isVisible: true, stepData })
    next(stepData)
  }, [scanState, next])

  const handleViewMemberCard = useCallback(() => {
    // Logic for member card view
  }, [])

  const resetData = useCallback(() => {
    setScanState({
      isScanning: false,
      isProcessing: false,
      isCompleted: false,
      cccdData: null
    })
    setDisplayState({ isVisible: false, stepData: null })
    form.resetFields()
  }, [form])

  if (displayState.isVisible) {
    return (
      <DisplayCCCDInfo
        memberData={displayState.stepData}
        onViewMemberCard={handleViewMemberCard}
        onBack={resetData}
      />
    )
  }

  return (
    <div className="business-register__step" style={{ background: '#f5f7fa', Height: '100vh' }}>
      <div style={{ paddingTop: '20px', margin: '0 auto' }}>
        <div style={{ textAlign: 'center', marginBottom: '20px' }}>
          <Title level={2} style={{ color: '#1677ff', fontWeight: 700, marginBottom: 10 }}>
            <QrcodeOutlined style={{ marginRight: '12px', fontSize: '32px' }} />
            Quét QR Hội Viên
          </Title>
          <Text type="secondary" style={{ fontSize: '18px', color: '#6b7280' }}>
            Chọn một trong các phương thức dưới đây để quét thông tin từ QR Hội Viên của bạn
          </Text>
        </div>

        <Row justify="center">
          <Col xs={24} sm={22} >
            <StyledCard>
              <Tabs
                defaultActiveKey="1"
                centered
                tabBarStyle={{fontSize: '16px', fontWeight: 500 }}
              >
                <TabPane
                  tab={
                    <span>
                      <ScanOutlined style={{ marginRight: 8 }} /> Quét bằng máy Scan
                    </span>
                  }
                  key="1"
                >
                  <ScanTab
                    scanState={scanState}
                    handleHardwareScan={handleHardwareScan}
                    resetData={resetData}
                    handleConfirm={handleConfirm}
                  />
                </TabPane>

                <TabPane
                  tab={
                    <span>
                      <UploadOutlined style={{ marginRight: 8 }} /> Upload ảnh
                    </span>
                  }
                  key="2"
                >
                  <UploadTab
                    onQRScanned={handleQRScanned}
                    onImageUploaded={handleImageUploaded}
                    title="Quét CCCD từ ảnh"
                    description="Chọn ảnh có chứa mã QR để tự động lấy thông tin"
                    acceptedFormats="image/png, image/jpeg"
                    maxFileSize={5}
                    showPreview
                  />
                </TabPane>

                <TabPane
                  tab={
                    <span>
                      <CameraOutlined style={{ marginRight: 8 }} /> Quét camera
                    </span>
                  }
                  key="3"
                >
                  <CameraTab/>
                </TabPane>
              </Tabs>
            </StyledCard>
          </Col>
        </Row>
      </div>

      {scanState.isScanning && (
        <ScanQR
          open={scanState.isScanning}
          onCancel={handleCloseCameraScan}
          onOk={handleCameraScanResult}
        />
      )}
    </div>
  )
}

export default ScanQRInfo
