import { CameraOutlined } from "@ant-design/icons"
import { Card, Form, message } from "antd"
import { useState } from "react"
import ButtonCustom from "src/components/MyButton/Button"
import RegionService from "src/services/RegionService"
import DisplayCCCDInfo from "../DisplayCCCDInfo"
import { parseDate, parseIDCardData } from "../../utils/cccdUtils"
import parseScannedCCCDData from "../parseScannedCCCDData"
import QuickScanQR from "./QuickScanQR"
import GuestService from "src/services/GuestService"

const CameraTab = ({ form, updateMetadata }) => {
  const [scanQRVisible, setScanQRVisible] = useState(false)
  const [cccdData, setCccdData] = useState(null)

  const handleScanResult = async data => {
    try {
      if (!data?.raw) throw new Error("Không có dữ liệu QR")

      const parsedID = parseIDCardData(data.raw)

      if (parsedID) {
        updateMetadata?.({ isAutoFilled: true })
        message.success("Quét CCCD thành công!")
        setScanQRVisible(false)

        const birthDate = parseDate(parsedID.birthDate)
        const issueDate = parseDate(parsedID.issueDate)

        form.setFieldsValue({
          cccdId: parsedID.id,
          fullName: parsedID.name,
          birthDate,
          gender: parsedID.gender,
          issueDate,
          originalAddress: parsedID.address,
        })

        if (parsedID.address) {
          convertCCCDAddress(parsedID.address)
        }
      } else {
        const parsedMember = parseScannedCCCDData(data.raw)
        if (parsedMember?.memberId && parsedMember?.memberType) {
          message.success("QR hội viên hợp lệ! Đang tải thông tin...")
          const res = await GuestService.getMemberDetail({
            memberId: parsedMember.memberId,
            memberType: parsedMember.memberType,
          })
          if (res?.isError) {
            message.error("Không tìm thấy thông tin hội viên.")
          } else {
            setCccdData(res.Object)
          }
          setScanQRVisible(false)
        } else {
          throw new Error("QR không hợp lệ.")
        }
      }
    } catch (error) {
      console.error("Lỗi xử lý mã QR:", error)
      message.error("Không thể xử lý mã QR.")
    }
  }

  const convertCCCDAddress = async address => {
    try {
      const response = await RegionService.convertRegion({
        address: address.trim(),
      })

      if (response?.Object) {
        const addressData = response.Object

        form.setFieldsValue({
          provinceId: addressData.ProvinceID || null,
          districtId: addressData.DistricID || null,
          wardId: addressData.WardID || null,
          streetAddress: addressData.Address || "",
        })
      } else {
        message.warning("Không thể phân tích địa chỉ, vui lòng nhập thủ công")
      }
    } catch (error) {
      console.error("Lỗi phân tích địa chỉ:", error)
      message.warning("Không thể phân tích địa chỉ, vui lòng nhập thủ công")
    }
  }

  if (cccdData) {
    return (
      <DisplayCCCDInfo
        memberData={cccdData}
        onBack={() => setCccdData(null)}
        onViewMemberCard={() => console.log("Xem thẻ hội viên")}
      />
    )
  }

  return (
    <div className="camera-only-tab">
      <Form form={form} layout="vertical">
        <Card
          hoverable
          style={{ border: "2px dashed #009688" }}
          onClick={() => setScanQRVisible(true)}
        >
          <div className="text-center p-2">
            <CameraOutlined style={{ fontSize: "48px" }} />
            <div className="mb-16">
              Dùng camera để quét mã QR CCCD hoặc Hội Viên
            </div>
            <ButtonCustom>Mở camera</ButtonCustom>
          </div>
        </Card>

        {scanQRVisible && (
          <QuickScanQR
            form={form}
            updateMetadata={updateMetadata}
            onCancel={() => setScanQRVisible(false)}
          />
        )}
      </Form>
    </div>
  )
}

export default CameraTab
