import { BrowserQRCodeReader } from "@zxing/browser"
import { Button, message } from "antd"
import PropTypes from "prop-types"
import { useEffect, useRef, useState } from "react"
import GuestService from "src/services/GuestService"
import RegionService from "src/services/RegionService"
import { parseDate, parseIDCardData } from "../../utils/cccdUtils"
import DisplayCCCDInfo from "../DisplayCCCDInfo"
import parseScannedCCCDData from "../parseScannedCCCDData"

const QuickScanQR = ({ form, updateMetadata, onCancel }) => {
  const videoRef = useRef(null)
  const codeReaderRef = useRef(null)
  const [cccdData, setCccdData] = useState(null)
  const [scanning, setScanning] = useState(true)
  const hasScannedRef = useRef(false)

  useEffect(() => {
    if (scanning) {
      hasScannedRef.current = false
      codeReaderRef.current = new BrowserQRCodeReader(undefined, {
        delayBetweenScanAttempts: 100,
      })
      startScan()
    }
    return () => {
      stopScan()
    }
  }, [scanning])

  const startScan = async () => {
    try {
      const devices = await BrowserQRCodeReader.listVideoInputDevices()
      const backCamera =
        devices.find(d => /back|rear|environment/i.test(d.label)) || devices[0]

      await codeReaderRef.current.decodeFromVideoDevice(
        backCamera.deviceId,
        videoRef.current,
        async (result, error) => {
          if (hasScannedRef.current) return
          if (result) {
            hasScannedRef.current = true
            stopScan()
            const raw = result.getText()
            await handleScanResult({ raw })
          }
          if (error && error.name !== "NotFoundException") {
            console.error("Lỗi khi quét:", error)
          }
        },
      )
    } catch (error) {
      console.error("Không thể khởi động camera:", error)
      message.error("Không thể khởi động camera.")
      handleClose()
    }
  }

  const stopScan = () => {
    try {
      codeReaderRef.current?.reset?.()
      const video = videoRef.current
      if (video && video.srcObject) {
        video.srcObject.getTracks().forEach(track => track.stop())
        video.srcObject = null
      }
      video?.pause?.()
      video && (video.src = "")
      video?.load?.()
    } catch (e) {}
  }

  const handleClose = () => {
    stopScan()
    setScanning(false)
    onCancel?.()
  }

  const convertCCCDAddress = async address => {
    try {
      const response = await RegionService.convertRegion({
        address: address.trim(),
      })

      if (response?.Object) {
        const { ProvinceID, DistricID, WardID, Address } = response.Object
        form.setFieldsValue({
          provinceId: ProvinceID || null,
          districtId: DistricID || null,
          wardId: WardID || null,
          streetAddress: Address || "",
        })
      } else {
        message.warning("Không thể phân tích địa chỉ từ CCCD.")
      }
    } catch (err) {
      console.error("Lỗi phân tích địa chỉ:", err)
      message.warning("Không thể phân tích địa chỉ.")
    }
  }

  const handleScanResult = async ({ raw }) => {
    try {
      const parsedCCCD = parseIDCardData(raw)
      if (parsedCCCD?.id) {
        message.success("Đã quét CCCD thành công!")
        updateMetadata?.({ isAutoFilled: true })

        form.setFieldsValue({
          cccdId: parsedCCCD.id,
          fullName: parsedCCCD.name,
          birthDate: parseDate(parsedCCCD.birthDate),
          gender: parsedCCCD.gender,
          issueDate: parseDate(parsedCCCD.issueDate),
          originalAddress: parsedCCCD.address,
        })

        if (parsedCCCD.address) {
          await convertCCCDAddress(parsedCCCD.address)
        }
        setScanning(false)
      } else {
        const parsed = parseScannedCCCDData(raw)
        if (parsed?.memberId && parsed?.memberType) {
          const res = await GuestService.getMemberDetail({
            memberId: parsed.memberId,
            memberType: parsed.memberType,
          })

          if (res?.isError) {
            message.error("Không tìm thấy thông tin hội viên.")
            setScanning(false)
            onCancel?.()
          } else if (res?.Object) {
            message.success("QR hội viên hợp lệ! Đang lấy thông tin...")
            setCccdData(res.Object)
            setScanning(false)
          } else {
            message.error("Thông tin hội viên không hợp lệ.")
            setScanning(false)
            onCancel?.()
          }
        } else {
          message.error("QR không hợp lệ.")
          setScanning(false)
          onCancel?.()
        }
      }
    } catch (err) {
      console.error("Lỗi xử lý QR:", err)
      message.error("Không thể xử lý mã QR.")
      setScanning(false)
      onCancel?.()
    }
  }

  if (cccdData) {
    return (
      <DisplayCCCDInfo
        memberData={cccdData}
        onBack={() => {
          setCccdData(null)
          setScanning(true)
        }}
        onViewMemberCard={() => console.log("Xem thẻ hội viên")}
      />
    )
  }

  if (!scanning) return null

  return (
    <div style={{ textAlign: "center", padding: 24 }}>
      <h3>Đang quét mã QR...</h3>
      <video
        ref={videoRef}
        autoPlay
        muted
        playsInline
        style={{
          width: "100%",
          maxWidth: 480,
          borderRadius: 8,
          border: "2px solid #1890ff",
        }}
      />
      <div style={{ marginTop: 20 }}>
        <Button danger onClick={handleClose}>
          Đóng camera
        </Button>
      </div>
    </div>
  )
}

QuickScanQR.propTypes = {
  form: PropTypes.object.isRequired,
  updateMetadata: PropTypes.func,
  onCancel: PropTypes.func,
}

export default QuickScanQR
