import {
  ApartmentOutlined,
  CalendarOutlined,
  DownloadOutlined,
  HomeOutlined,
  IdcardOutlined,
  MailOutlined,
  PhoneOutlined,
  ProfileOutlined,
  SolutionOutlined,
  UserOutlined,
} from "@ant-design/icons"
import { Card, Col, Row, Space, Typography } from "antd"
import dayjs from "dayjs"
import PropTypes from "prop-types"
import BusinessMemberInfo from "./BusinessMemberInfo"
import CustomMemberCard from "./ProfessionalMemberCard"
import * as htmlToImage from "html-to-image"
import { useRef } from "react"
import ButtonCustom from "src/components/MyButton/Button"
import "./DisplayCCCDinfo.scss"
import { LocationEdit, Mail } from "lucide-react"

const { Title, Text } = Typography

const DisplayCCCDInfo = ({ memberData }) => {
  const formatDate = dateString =>
    dateString && !dateString.startsWith("0001")
      ? dayjs(dateString).format("DD/MM/YYYY")
      : "Chưa có thông tin"

  const isBusiness = memberData.MemberType === "Doanh nghiệp"

  const cardRef = useRef(null)

  const handleDownload = async () => {
    if (!cardRef.current) return

    try {
      const dataUrl = await htmlToImage.toPng(cardRef.current, {
        cacheBust: true,
        style: { backgroundColor: "#fff" },
      })

      const link = document.createElement("a")
      link.href = dataUrl
      link.download = "the-hoi-vien.png"
      document.body.appendChild(link)
      link.click()
      document.body.removeChild(link)
    } catch (error) {
      console.error("Lỗi khi tạo ảnh:", error)
    }
  }

  //- khối thông tin cá nhân
  const renderPersonalInfo = () => (
    <>
      <Col xs={24} sm={12} md={8}>
        <InfoRow
          label="Họ tên"
          value={memberData.FullName}
          icon={<CalendarOutlined />}
        />
      </Col>
      <Col xs={24} sm={12} md={8}>
        <InfoRow
          label="Ngày sinh"
          value={formatDate(memberData.DateOfBirth)}
          icon={<CalendarOutlined />}
        />
      </Col>
      <Col xs={24} sm={12} md={8}>
        <InfoRow
          label="Số CCCD"
          value={memberData.Identification}
          icon={<IdcardOutlined />}
        />
      </Col>
      <Col xs={24} sm={12} md={8}>
        <InfoRow
          label="Nghề nghiệp"
          value={memberData.Occupation}
          icon={<SolutionOutlined />}
        />
      </Col>
      <Col xs={24} sm={12} md={8}>
        <InfoRow
          label="Số điện thoại"
          value={memberData.PhoneNumber}
          icon={<PhoneOutlined />}
        />
      </Col>
      <Col xs={24} sm={12} md={8}>
        <InfoRow
          label="Loại hội viên"
          value={memberData.MemberType}
          icon={<ApartmentOutlined />}
        />
      </Col>
    </>
  )

  const renderBusinessInfo = () => (
    <>
      <Col xs={24} sm={12} md={8} className="checkClassName">
        <InfoRow
          label="Tên doanh nghiệp"
          value={memberData.OrganizationName}
          icon={<IdcardOutlined />}
        />
      </Col>
      <Col xs={24} sm={12} md={8}>
        <InfoRow
          label="Mã số thuế"
          value={memberData.TaxCode}
          icon={<IdcardOutlined />}
        />
      </Col>
      <Col xs={24} sm={12} md={8}>
        <InfoRow
          label="Ngày cấp MST"
          value={formatDate(memberData.TaxIssuedDate)}
          icon={<CalendarOutlined />}
        />
      </Col>
      <Col xs={24} sm={12} md={8}>
        <InfoRow
          label="Người đại diện"
          value={memberData.RepresentativeName}
          icon={<UserOutlined />}
        />
      </Col>
      <Col xs={24} sm={12} md={8}>
        <InfoRow
          label="Chức vụ đại diện"
          value={memberData.RepresentativePosition}
          icon={<ProfileOutlined />}
        />
      </Col>
      <Col xs={24} sm={12} md={8}>
        <InfoRow
          label="SĐT đại diện"
          value={memberData.RepresentativePhoneNumber}
          icon={<PhoneOutlined />}
        />
      </Col>
      <Col xs={24} sm={12} md={8}>
        <InfoRow label="Email" value={memberData.Email} icon={<MailOutlined />} />
      </Col>
      <Col xs={24} sm={12} md={8}>
        <InfoRow
          label="Địa chỉ doanh nghiệp"
          value={memberData.Address}
          icon={<LocationEdit />}
        />
      </Col>
    </>
  )

  return (
    <div>
      {/* Khối thẻ hội viên */}
      <Row gutter={[16, 16]} className="display-cccd-info">
        {/* Thẻ hội viên */}
        <Col
          xs={{ span: 24, order: 1 }}
          lg={{ span: 14, order: 2 }}
          className="display-cccd-info__member-card"
        >
          <Card
            className="display-cccd-info__member-card-inner"
            style={{ borderRadius: 16, border: "none", overflow: "hidden" }}
          >
            <Row
              justify="space-between"
              className="display-cccd-info__member-card-header"
            >
              <Title level={4} className="display-cccd-info__title">
                Thẻ hội viên
              </Title>
              <ButtonCustom
                type="primary"
                onClick={handleDownload}
                icon={<DownloadOutlined />}
                className="display-cccd-info__download-btn"
              >
                Tải thẻ về
              </ButtonCustom>
            </Row>
            <div ref={cardRef} className="display-cccd-info__member-card-body">
              {memberData.MemberType === "Doanh nghiệp" ? (
                <BusinessMemberInfo memberData={memberData} />
              ) : (
                <CustomMemberCard memberData={memberData} />
              )}
            </div>
          </Card>
        </Col>

        {/* Thông tin chi tiết */}
        <Col
          xs={{ span: 24, order: 2 }}
          lg={{ span: 10, order: 1 }}
          className="display-cccd-info__details"
        >
          <Col>
            <Card
              className="display-cccd-info__details-card"
              style={{ border: "none" }}
            >
              <Row>
                <Title level={4} className="display-cccd-info__title">
                  {isBusiness ? "Thông tin doanh nghiệp" : "Thông tin cá nhân"}
                </Title>
              </Row>
              <Row gutter={[32, 24]} className="display-cccd-info__info-rows">
                {isBusiness ? renderBusinessInfo() : renderPersonalInfo()}
              </Row>
            </Card>

            <Card
              className="display-cccd-info__details-card"
              style={{ border: "none" }}
            >
              <Row>
                <Title level={4} className="display-cccd-info__title">
                  Chi tiết hội viên
                </Title>
              </Row>
              <Space
                direction="vertical"
                size="large"
                style={{ width: "100%" }}
                className="display-cccd-info__info-list"
              >
                <InfoItem
                  label="Địa chỉ cư trú"
                  value={memberData.ResidenceAddress}
                  icon={
                    <HomeOutlined style={{ color: "#1677ff", fontSize: 20 }} />
                  }
                  className="display-cccd-info__info-item"
                />
                <InfoItem
                  label="Địa chỉ liên hệ"
                  value={memberData.ContactAddress}
                  icon={
                    <HomeOutlined style={{ color: "#1677ff", fontSize: 20 }} />
                  }
                  className="display-cccd-info__info-item"
                />
                <InfoItem
                  label="Ngày cấp"
                  value={formatDate(memberData.IdentificationIssueDate)}
                  icon={
                    <CalendarOutlined
                      style={{ color: "#1677ff", fontSize: 20 }}
                    />
                  }
                  className="display-cccd-info__info-item"
                />
              </Space>
            </Card>
          </Col>
        </Col>
      </Row>
    </div>
  )
}

const InfoItem = ({ label, value, icon, color = "" }) => (
  <div
    style={{
      display: "flex",
      alignItems: "flex-start",
      gap: 16,
      padding: "16px 20px",
      borderRadius: 12,
      border: `1px solid ${color}`,
      boxShadow: "0 2px 8px rgba(0, 0, 0, 0.04)",
      transition: "all 0.3s",
    }}
  >
    <div style={{ fontSize: 22, color }}>{icon}</div>
    <div>
      <Text
        style={{ fontSize: 12, color: "#64748b", textTransform: "uppercase" }}
      >
        {label}
      </Text>
      <br />
      <Text strong style={{ fontSize: 16 }}>
        {value || "—"}
      </Text>
    </div>
  </div>
)

const InfoRow = ({ label, value, icon }) => (
  <div style={{ display: "flex", alignItems: "flex-start", gap: 12 }}>
    <div style={{ color: "#2563eb", fontSize: 20 }} className="row-icon">
      {icon}
    </div>
    <div className="row-item">
      <Text
        strong
        style={{ color: "#1f2937", fontSize: 15 }}
        className="row-label"
      >
        {label}
      </Text>
      <Text
        style={{
          color: "#4b5563",
          display: "block",
          marginTop: 4,
          fontSize: 15,
        }}
        className="row-value"
      >
        {value || "Chưa có thông tin"}
      </Text>
    </div>
  </div>
)

DisplayCCCDInfo.propTypes = {
  memberData: PropTypes.object.isRequired,
  onBack: PropTypes.func.isRequired,
}

export default DisplayCCCDInfo
